964	        static constexpr std::string_view return_token = "<|return|>";
965	        static constexpr std::string_view end_token    = "<|end|>";
966	        if (size_t pos = prompt.rfind(return_token); pos != std::string::npos) {
967	            prompt.replace(pos, return_token.length(), end_token);
