985	
986	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
987	        auto start           = p.rule("start", p.literal("<|start|>assistant"));
988	        auto end             = p.rule("end", p.literal("<|end|>"));
989	        auto content         = p.rule("message-content", p.until("<|end|>"));
990	        auto channel         = p.literal("<|channel|>") + (p.literal("commentary") | p.literal("analysis"));
991	        auto constrain_type  = p.chars("[A-Za-z0-9_-]", 1, -1);
992	
993	        // Occasionally, gpt-oss-20b will prefix channels with this commentary
994	        auto stray_commentary = p.optional(p.literal("<|channel|>commentary") + p.optional(p.literal(" to=assistant")));
995	        auto start_analysis = stray_commentary + p.literal("<|channel|>analysis<|message|>");
996	
997	        if (extract_reasoning) {
998	            p.rule("analysis", start_analysis + p.reasoning(content) + end);
999	        } else {
1000	            p.rule("analysis", p.content(start_analysis + content + end));
1001	        }
1002	
1003	        auto analysis = p.ref("analysis");
1004	        auto preamble = p.rule("preamble", p.literal("<|channel|>commentary<|message|>") + p.content(content) + end);
1005	        auto final_msg = p.rule("final", stray_commentary + p.literal("<|channel|>final<|message|>") + p.content(content));
