static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Mistral Instruct v0.3 prepends the system message to the first user turn
    // inside the [INST] block. Build an adjusted message list that merges a
    // leading system message into the first user message before template rendering.
    auto adjusted_messages = inputs.messages;
    if (!adjusted_messages.empty() && adjusted_messages.front().value("role", "") == "system") {
        std::string sys_content = adjusted_messages.front().value("content", "");
        adjusted_messages.erase(adjusted_messages.begin());
        if (!adjusted_messages.empty() && adjusted_messages.front().value("role", "") == "user") {
            std::string user_content = adjusted_messages.front().value("content", "");
            adjusted_messages.front()["content"] = sys_content + "\n\n" + user_content;
        }
    }

    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens  = { "[INST]", "[/INST]", "</s>" };

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        return p.literal(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    return data;
}

